// src/components/TicketCard.tsx
import React from "react";
import QRCode from "react-qr-code";
import {
    Card,
    CardContent,
    CardHeader,
    Typography,
    Divider,
    Box
} from "@mui/material";

interface TicketCardProps {
    ticketCode: string;
    mode: string;
    price: number;
    expiration: string;
}

const TicketCard: React.FC<TicketCardProps> = ({ ticketCode, mode, price, expiration }) => {
    return (
        <Card sx={{ maxWidth: 320, textAlign: "center", boxShadow: 3, borderRadius: 3 }}>
            <CardHeader
                title="Ticket"
                subheader={`Mode: ${mode}`}
                titleTypographyProps={{ variant: "h6" }}
                subheaderTypographyProps={{ variant: "subtitle1" }}
            />
            <Divider />
            <CardContent>
                <Box sx={{ display: "flex", justifyContent: "center", mb: 2 }}>
                    <QRCode value={ticketCode} size={120} />
                </Box>
                <Typography variant="body1" gutterBottom>
                    <strong>Code:</strong> {ticketCode}
                </Typography>
                <Typography variant="body1">
                    <strong>Price:</strong> ${price.toFixed(2)}
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                    <strong>Expires:</strong> {new Date(expiration).toLocaleString()}
                </Typography>
            </CardContent>
        </Card>
    );
};

export default TicketCard;
