// src/services/ticketService.ts
import axios from "axios";

export interface TicketResponse {
    ticketCode: string;
    mode: string;
    price: number;
    expiration: string; // ISO string
    // (we're not requiring status here for this step)
}

const authAxios = axios.create({
    baseURL: "http://localhost:8080/api/tickets"
});

authAxios.interceptors.request.use((config) => {
    const token = localStorage.getItem("token");
    if (token) {
        config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
});

export const getAllTickets = async (): Promise<TicketResponse[]> => {
    const res = await authAxios.get<TicketResponse[]>("");
    return res.data;
};

export const invalidateTicket = async (ticketCode: string): Promise<void> => {
    // POST (or PUT) to an invalidate endpoint. Adjust path if your backend differs.
    await authAxios.post(`/${encodeURIComponent(ticketCode)}/invalidate`);
};

export const addTicket = async (mode: string): Promise<TicketResponse> => {
    const res = await authAxios.post<TicketResponse>("", { mode: mode }, { headers: { "Content-Type": "application/json" } });
    return res.data;
};
