// src/pages/ViewTickets.tsx
import React, { useEffect, useState } from "react";
import { getAllTickets, invalidateTicket, TicketResponse } from "../services/ticketService";
import {
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Paper,
    Typography,
    CircularProgress,
    Button,
    IconButton
} from "@mui/material";
import { useNavigate } from "react-router-dom";

const ViewTickets: React.FC = () => {
    const [tickets, setTickets] = useState<TicketResponse[]>([]);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchTickets = async () => {
            try {
                const data = await getAllTickets();
                setTickets(data);
            } catch (err) {
                console.error("Error fetching tickets:", err);
                navigate("/login"); // redirect if unauthorized
            } finally {
                setLoading(false);
            }
        };
        fetchTickets();
    }, [navigate]);

    const handleInvalidate = async (ticketCode: string) => {
        try {
            await invalidateTicket(ticketCode);
            // remove the invalidated ticket from UI (simple behavior)
            setTickets(prev => prev.filter(t => t.ticketCode !== ticketCode));
        } catch (err) {
            console.error("Error invalidating ticket:", err);
            // optionally show an error snackbar/toast here
        }
    };

    if (loading) {
        return (
            <div style={{ display: "flex", justifyContent: "center", marginTop: "2rem" }}>
                <CircularProgress />
            </div>
        );
    }

    return (
        <div style={{ padding: "20px" }}>
            <Typography variant="h4" gutterBottom>
                All Tickets
            </Typography>
            {tickets.length === 0 ? (
                <Typography>No tickets found.</Typography>
            ) : (
                <TableContainer component={Paper}>
                    <Table>
                        <TableHead>
                            <TableRow>
                                <TableCell><strong>Ticket Code</strong></TableCell>
                                <TableCell><strong>Mode</strong></TableCell>
                                <TableCell><strong>Price</strong></TableCell>
                                <TableCell><strong>Expiration</strong></TableCell>
                                <TableCell align="center"><strong>Invalidate</strong></TableCell>
                            </TableRow>
                        </TableHead>
                        <TableBody>
                            {tickets.map((ticket) => (
                                <TableRow key={ticket.ticketCode}>
                                    <TableCell>{ticket.ticketCode}</TableCell>
                                    <TableCell>{ticket.mode}</TableCell>
                                    <TableCell>${ticket.price.toFixed(2)}</TableCell>
                                    <TableCell>{new Date(ticket.expiration).toLocaleString()}</TableCell>
                                    <TableCell align="center">
                                        <IconButton
                                            aria-label={`invalidate ${ticket.ticketCode}`}
                                            size="small"
                                            onClick={() => handleInvalidate(ticket.ticketCode)}
                                        >
                                            {/* add close icon */}
                                            <span style={{ fontSize: '1.5rem', color: 'red' }}>&times;</span>
                                        </IconButton>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </TableContainer>
            )}

            <Button
                variant="outlined"
                color="secondary"
                sx={{ mt: 2 }}
                onClick={() => {
                    localStorage.removeItem("token");
                    navigate("/login");
                }}
            >
                Logout
            </Button>
        </div>
    );
};

export default ViewTickets;
