// src/pages/AddTicket.tsx
import React, { useState } from "react";
import { addTicket, TicketResponse } from "../services/ticketService";
import TicketCard from "../components/TicketCard";
import {
    Button,
    TextField,
    MenuItem,
    Typography,
    Box
} from "@mui/material";
import { useNavigate } from "react-router-dom";

const AddTicket: React.FC = () => {
    const [mode, setMode] = useState("BASIC");
    const [ticket, setTicket] = useState<TicketResponse | null>(null);
    const navigate = useNavigate();

    const handleAddTicket = async () => {
        try {
            const newTicket = await addTicket(mode);
            setTicket(newTicket);
        } catch (error) {
            console.error("Error creating ticket:", error);
            navigate("/login"); // redirect if unauthorized
        }
    };

    return (
        <Box sx={{ padding: 3 }}>
            <Typography variant="h4" gutterBottom>Add Ticket</Typography>

            <TextField
                select
                label="Validation Mode"
                value={mode}
                onChange={(e) => setMode(e.target.value)}
                fullWidth
                margin="normal"
            >
                <MenuItem value="BASIC">Basic</MenuItem>
                <MenuItem value="FULL">Full</MenuItem>
                <MenuItem value="EXTRA">Extra</MenuItem>
            </TextField>

            <Button
                variant="contained"
                color="primary"
                onClick={handleAddTicket}
                sx={{ mt: 2 }}
            >
                Add Ticket
            </Button>

            {ticket && (
                <Box sx={{ mt: 3 }}>
                    <Typography variant="h6">Created Ticket:</Typography>
                    <TicketCard {...ticket} />
                </Box>
            )}
        </Box>
    );
};

export default AddTicket;
